VALUES
  ('optician-moex-01369', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '隱形眼鏡透氧率（oxygen permeability）為 60，當中心厚度為 0.07 mm，則隱形眼鏡的傳氧率（oxygen transmissibility）為多少？', '["42.0", "85.7", "8.6", "67.0"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01370', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式矽水膠隱形眼鏡的敘述，下列何者錯誤？', '["為高透氧鏡片，可降低角膜血管新生之發生", "適合眼睛乾澀者配戴，因鏡片含水量低", "與水膠鏡片相比，其彈性係數（modulusofelasticity）較低，因此鏡片較為柔軟", "鏡片含矽的比例越高者越透氧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01371', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡含水量的敘述，下列何者正確？', '["低含水量的鏡片較易吸附污垢", "乾眼症患者較適合高含水量材質", "水膠鏡片增加含水量會降低折射率", "低含水量的鏡片材質較不穩定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01372', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡材質單體-甲基丙烯酸甲酯（methylmethacrylate,MMA）的敘述，下列何者錯誤？', '["具良好的光學透明度", "用於製作硬式鏡片和軟式鏡片的材料", "可用來增加聚合物的含水量", "能增加聚合物的強度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01373', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡保養液主要成分的敘述，下列何者錯誤？', '["乙二胺四乙酸（EDTA）其實並不是真正的防腐劑，而是屬於一種螯合劑", "EDTA經常與氯化苯二甲烴銨（benzalkoniumchloride,BAK）或其他的防腐劑合併使用", "EDTA與其他的防腐劑併用可以提昇一般防腐劑在硬式透氣隱形眼鏡的清潔殺菌能力", "EDTA與其他的防腐劑併用可以提昇其清潔殺菌能力，但是對抗綠膿桿菌反而會因拮抗而效果減弱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01374', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式隱形眼鏡鏡片消毒溶液敘述，下列何者錯誤？', '["硬式隱形眼鏡的去蛋白消毒與軟式隱形眼鏡的去蛋白消毒一樣重要", "使用去蛋白藥水系統的頻率，取決於鏡片材料和去蛋白系統中活性成分的強度", "患者個人的因素並不會影響去蛋白系統的使用方式", "患者的鏡片上若有明顯蛋白沉積，會建議患者更頻繁去蛋白清潔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01375', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '常用隱形眼鏡清潔護理液中，那一種防腐劑最常造成角膜及結膜上皮毒性反應？', '["甲基汞（methylmercury）", "氯己定（chlorhexidine）", "苯甲醯胺（benzamide）", "乙二胺四乙酸"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "efead02933a4", "answer_pdf_sha1": "f889fe1f73a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "402", "s": "1508", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
